{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyOlj1NdUKRsEMhSFjwSgMQu"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":1,"metadata":{"colab":{"base_uri":"https://localhost:8080/"},"id":"BtqQeRvs5ABv","executionInfo":{"status":"ok","timestamp":1777477114560,"user_tz":-330,"elapsed":22,"user":{"displayName":"Nandana S","userId":"09011285804801661207"}},"outputId":"44ba566e-75f8-41d4-cb8f-804acb866f19"},"outputs":[{"output_type":"stream","name":"stdout","text":["Count of 20: 2\n","Updated nums: [10, 30, 20, 40, 50]\n","\n","Max: 25\n","Min: 5\n","Sum: 75\n","\n","Updated items: [4, 3, 2, 1]\n","\n","Student values: [80, 60, 70]\n","\n","Frequency dictionary: {1: 1, 2: 2, 3: 3, 4: 1}\n","\n","Final list: [1, 2, 3, 4, 5]\n","\n","Key with highest value: C\n"]}],"source":["# -------------------------------\n","# 6. List Operations\n","# -------------------------------\n","nums = [10, 20, 30, 20, 40]\n","\n","# Count occurrences of 20\n","print(\"Count of 20:\", nums.count(20))\n","\n","# Remove one occurrence of 20\n","nums.remove(20)\n","\n","# Add 50\n","nums.append(50)\n","\n","print(\"Updated nums:\", nums)\n","\n","\n","# -------------------------------\n","# 7. Find max, min, sum\n","# -------------------------------\n","data = [5, 10, 15, 20, 25]\n","\n","print(\"\\nMax:\", max(data))\n","print(\"Min:\", min(data))\n","print(\"Sum:\", sum(data))\n","\n","\n","# -------------------------------\n","# 8. List modifications\n","# -------------------------------\n","items = [1, 2, 3]\n","\n","# Add two elements\n","items.append(4)\n","items.append(5)\n","\n","# Remove last element\n","items.pop()\n","\n","# Reverse list\n","items.reverse()\n","\n","print(\"\\nUpdated items:\", items)\n","\n","\n","# -------------------------------\n","# 9. Dictionary operations\n","# -------------------------------\n","student = {\"A\": 50, \"B\": 60}\n","\n","# Add new student\n","student[\"C\"] = 70\n","\n","# Update marks of A\n","student[\"A\"] = 80\n","\n","# Get all values\n","print(\"\\nStudent values:\", list(student.values()))\n","\n","\n","# -------------------------------\n","# 10. Frequency count\n","# -------------------------------\n","nums2 = [1, 2, 2, 3, 3, 3, 4]\n","\n","freq = {}\n","for num in nums2:\n","    freq[num] = nums2.count(num)\n","\n","print(\"\\nFrequency dictionary:\", freq)\n","\n","\n","# -------------------------------\n","# 11. Combine, remove duplicates, sort\n","# -------------------------------\n","list1 = [1, 2, 3]\n","list2 = [3, 4, 5]\n","\n","combined = list1 + list2\n","unique = list(set(combined))\n","unique.sort()\n","\n","print(\"\\nFinal list:\", unique)\n","\n","\n","# -------------------------------\n","# Bonus: Highest value key\n","# -------------------------------\n","data2 = {\"A\": 10, \"B\": 20, \"C\": 30}\n","\n","max_key = max(data2, key=data2.get)\n","print(\"\\nKey with highest value:\", max_key)"]}]}